+        }
+        // Shift.
+        for _ in 0..200 {
+            m.observe_and_update(&[3u8; N]);
+        }
+        // Recover.
+        for _ in 0..1000 {
+            m.observe_and_update(&base);
+        }
+        assert_eq!(
+            m.state(),
+            MmdState::Conforming,
+            "should recover to Conforming after returning to baseline"
+        );
+    }
+
+    #[test]
+    fn rbf_kernel_self_is_one() {
