+        }
+        assert!(
+            m.mean_shift_norm() < 0.1,
+            "norm {} should be near zero at baseline",
+            m.mean_shift_norm()
+        );
+    }
+
+    #[test]
+    fn summary_consistent() {
+        let mut m = KernelMmdMonitor::new();
+        for _ in 0..100 {
+            m.observe_and_update(&[1u8; N]);
+        }
+        let s = m.summary();
